SELECT * FROM json_populate_recordset(NULL::public.prompt_knowledge, $SEED$[{"id":"92811f79-8b4e-4a47-a8ef-95add14756b3","tags":["camera","motion","technique"],"title":"Camera Movement Keywords","content":"Use specific camera terms: \"slow dolly in\", \"tracking shot\", \"crane shot upward\", \"handheld follow\", \"steadicam orbit\". These help AI models understand desired motion better than vague descriptions.","feature":"video","category":"technique","is_active":true,"created_at":"2026-02-18T09:17:34.18049+00:00","sort_order":1,"updated_at":"2026-02-18T09:17:34.18049+00:00","applicable_models":null,"applicable_platforms":null},{"id":"78399bc1-94f4-4400-95a7-48462d852d36","tags":["quality","cinematic","lighting"],"title":"Cinematic Quality Boosters","content":"Add quality descriptors: \"cinematic lighting\", \"shallow depth of field\", \"anamorphic lens flare\", \"film grain\", \"color graded\". Combine with specific lighting: \"golden hour\", \"neon-lit\", \"soft diffused\".","feature":"video","category":"technique","is_active":true,"created_at":"2026-02-18T09:17:34.18049+00:00","sort_order":2,"updated_at":"2026-02-18T09:17:34.18049+00:00","applicable_models":null,"applicable_platforms":null},{"id":"ad5c891a-cc24-4da8-8cba-384488d80af9","tags":["product","structure"],"title":"Product Video Structure","content":"Structure product prompts as: [Subject] + [Action] + [Setting] + [Style]. Example: \"Premium skincare bottle rotating slowly on marble surface, studio lighting, soft shadows, 4K quality\"","feature":"video","category":"technique","is_active":true,"created_at":"2026-02-18T09:17:34.18049+00:00","sort_order":3,"updated_at":"2026-02-18T09:17:34.18049+00:00","applicable_models":null,"applicable_platforms":null},{"id":"90047500-6417-4e9d-a600-c2dd3c7f1470","tags":["motion","description"],"title":"Motion Description","content":"Describe motion explicitly: \"smooth rotation 360 degrees\", \"gentle zoom from wide to close-up\", \"particles floating upward\". Avoid static descriptions for video — always include movement.","feature":"video","category":"technique","is_active":true,"created_at":"2026-02-18T09:17:34.18049+00:00","sort_order":4,"updated_at":"2026-02-18T09:17:34.18049+00:00","applicable_models":null,"applicable_platforms":null},{"id":"b4fcb2e3-0be0-472d-b9c2-4188dd0ccdcd","tags":["wan","model"],"title":"WAN 2.6 Best Practices","content":"WAN 2.6 excels at: text-to-video with complex scenes, smooth camera movements. Keep prompts detailed but under 200 words. Works best with realistic/cinematic styles.","feature":"video","category":"model_tip","is_active":true,"created_at":"2026-02-18T09:17:34.18049+00:00","sort_order":10,"updated_at":"2026-02-18T09:17:34.18049+00:00","applicable_models":["wan-2-6","wan-2-6-1080p"],"applicable_platforms":null},{"id":"c4d0ce19-83f4-4b8a-bc90-f54b113cf1ce","tags":["kling","model"],"title":"Kling V3 Pro Tips","content":"Kling V3 Pro is best for: character animation, face consistency, human motion. Add \"natural human movement\" for better results. Supports both T2V and I2V.","feature":"video","category":"model_tip","is_active":true,"created_at":"2026-02-18T09:17:34.18049+00:00","sort_order":11,"updated_at":"2026-02-18T09:17:34.18049+00:00","applicable_models":["kling-v3-pro","kling-v3-std"],"applicable_platforms":null},{"id":"d2a6110b-4ea0-49e3-9e42-e6bc23146a64","tags":["seedance","dance"],"title":"Seedance for Dance/Motion","content":"Seedance models specialize in dance and rhythmic motion. Include tempo descriptions: \"energetic dance moves\", \"slow graceful movements\". Best for I2V with reference images.","feature":"video","category":"model_tip","is_active":true,"created_at":"2026-02-18T09:17:34.18049+00:00","sort_order":12,"updated_at":"2026-02-18T09:17:34.18049+00:00","applicable_models":["seedance-pro-1080","seedance-lite-1080"],"applicable_platforms":null},{"id":"f7e19e74-3bab-453c-9910-f08ab4be9dd6","tags":["tiktok","social"],"title":"TikTok Video Guidelines","content":"TikTok: Use 9:16 ratio, 5-15 seconds, hook in first 2 seconds. Include text overlay areas. Fast-paced editing preferred. Audio strongly recommended.","feature":"video","category":"platform_best_practice","is_active":true,"created_at":"2026-02-18T09:17:34.18049+00:00","sort_order":20,"updated_at":"2026-02-18T09:17:34.18049+00:00","applicable_models":null,"applicable_platforms":["TikTok"]},{"id":"8684730f-e691-4ecc-a91f-e7bf99ec3078","tags":["instagram","social"],"title":"Instagram Reels Guidelines","content":"Instagram Reels: 9:16 ratio, 15-30 seconds optimal. Aesthetic quality matters more than TikTok. Clean compositions, good lighting. Music sync important.","feature":"video","category":"platform_best_practice","is_active":true,"created_at":"2026-02-18T09:17:34.18049+00:00","sort_order":21,"updated_at":"2026-02-18T09:17:34.18049+00:00","applicable_models":null,"applicable_platforms":["Instagram"]},{"id":"4187c8eb-58ab-4935-b32c-3726f70fa1b8","tags":["youtube","social"],"title":"YouTube Shorts Guidelines","content":"YouTube Shorts: 9:16 ratio, up to 60 seconds. More informational content works well. Clear storytelling structure. Thumbnail frame at start.","feature":"video","category":"platform_best_practice","is_active":true,"created_at":"2026-02-18T09:17:34.18049+00:00","sort_order":22,"updated_at":"2026-02-18T09:17:34.18049+00:00","applicable_models":null,"applicable_platforms":["YouTube"]},{"id":"953611f2-1ec0-46d5-bb68-81b1111867c5","tags":["composition","framing"],"title":"Composition Keywords","content":"Specify composition: \"rule of thirds\", \"centered composition\", \"negative space\", \"symmetrical layout\", \"dutch angle\". Combine with perspective: \"bird eye view\", \"low angle\", \"eye level\".","feature":"image","category":"technique","is_active":true,"created_at":"2026-02-18T09:17:34.18049+00:00","sort_order":1,"updated_at":"2026-02-18T09:17:34.18049+00:00","applicable_models":null,"applicable_platforms":null},{"id":"39e84b1d-3bd5-4781-8ae9-f1ed73257321","tags":["style","brand"],"title":"Style Consistency","content":"For brand consistency, specify style explicitly: \"flat design illustration\", \"3D rendered\", \"watercolor painting\", \"vector art\", \"photorealistic\". Add \"consistent style\" for series.","feature":"image","category":"technique","is_active":true,"created_at":"2026-02-18T09:17:34.18049+00:00","sort_order":2,"updated_at":"2026-02-18T09:17:34.18049+00:00","applicable_models":null,"applicable_platforms":null},{"id":"56334997-87d7-4840-b6e8-8ca57c834d61","tags":["product","photography"],"title":"Product Photography Prompts","content":"Product photos: include surface material (\"marble\", \"wood\", \"gradient backdrop\"), lighting setup (\"three-point lighting\", \"rim light\"), and mood (\"luxurious\", \"minimal\", \"vibrant\").","feature":"image","category":"technique","is_active":true,"created_at":"2026-02-18T09:17:34.18049+00:00","sort_order":3,"updated_at":"2026-02-18T09:17:34.18049+00:00","applicable_models":null,"applicable_platforms":null},{"id":"f3463512-59f9-47df-bdda-1721ddffea80","tags":["mystic","model"],"title":"Mystic Model Guide","content":"Mystic models produce high-quality photorealistic images. Best for: product photos, portraits, commercial imagery. Use detailed prompts with lighting and composition specifics.","feature":"image","category":"model_tip","is_active":true,"created_at":"2026-02-18T09:17:34.18049+00:00","sort_order":10,"updated_at":"2026-02-18T09:17:34.18049+00:00","applicable_models":["mystic","mystic-2k","mystic-4k"],"applicable_platforms":null},{"id":"e86e1fac-b174-4754-b74b-00b0225ce023","tags":["flux","model"],"title":"Flux Models Guide","content":"Flux models excel at: creative/artistic images, text rendering, concept art. Flux Pro for quality, Flux Turbo for speed. Good at following complex multi-element prompts.","feature":"image","category":"model_tip","is_active":true,"created_at":"2026-02-18T09:17:34.18049+00:00","sort_order":11,"updated_at":"2026-02-18T09:17:34.18049+00:00","applicable_models":["flux-2-pro","flux-2-turbo","flux-pro-v1-1"],"applicable_platforms":null},{"id":"51e4a0ee-18b1-410f-93aa-9fa93daccd27","tags":["composition","framing"],"title":"Rule of Thirds","content":"วางวัตถุหลักไว้ที่จุดตัด 1/3 ของภาพ ใช้คำว่า \"rule of thirds composition\" หรือ \"subject placed at left third\" เพื่อให้ภาพดูมีมิติและน่าสนใจมากขึ้น","feature":"image","category":"composition","is_active":true,"created_at":"2026-02-18T09:27:56.899401+00:00","sort_order":1,"updated_at":"2026-02-18T09:27:56.899401+00:00","applicable_models":null,"applicable_platforms":null},{"id":"6b44073c-7e2f-4891-900e-78e15d40ebda","tags":["composition","minimalist","ads"],"title":"Negative Space","content":"เว้นพื้นที่ว่างรอบวัตถุหลักเพื่อสร้างความโดดเด่น ใช้คำว่า \"minimalist composition with negative space\" เหมาะสำหรับโฆษณาที่ต้องใส่ข้อความเพิ่ม","feature":"image","category":"composition","is_active":true,"created_at":"2026-02-18T09:27:56.899401+00:00","sort_order":2,"updated_at":"2026-02-18T09:27:56.899401+00:00","applicable_models":null,"applicable_platforms":["instagram","facebook"]},{"id":"dd223eb1-84cd-48f6-abb3-d025d1b61181","tags":["composition","product","detail"],"title":"Close-up & Detail Shot","content":"ใช้ \"extreme close-up\" หรือ \"macro shot\" เพื่อเน้นรายละเอียดสินค้า เช่น texture ผิวหนัง เนื้อผ้า หรือส่วนประกอบอาหาร เพิ่ม \"shallow depth of field\" เพื่อให้โฟกัสชัดเฉพาะจุด","feature":"image","category":"composition","is_active":true,"created_at":"2026-02-18T09:27:56.899401+00:00","sort_order":3,"updated_at":"2026-02-18T09:27:56.899401+00:00","applicable_models":null,"applicable_platforms":null},{"id":"c923cbd4-716d-48cc-b217-c75a2f6b733d","tags":["lighting","warm","lifestyle"],"title":"Golden Hour Lighting","content":"ใช้ \"golden hour lighting\" หรือ \"warm sunset light\" เพื่อให้แสงอุ่นนุ่มนวล เหมาะกับ lifestyle, fashion, portrait ทำให้ภาพดู premium และมีอารมณ์","feature":"image","category":"lighting","is_active":true,"created_at":"2026-02-18T09:27:56.899401+00:00","sort_order":10,"updated_at":"2026-02-18T09:27:56.899401+00:00","applicable_models":null,"applicable_platforms":null},{"id":"ea4b1efe-4f71-47b8-9fd3-6b8cdcfe34f8","tags":["lighting","studio","product","ecommerce"],"title":"Studio Lighting for Products","content":"ใช้ \"professional studio lighting\" หรือ \"softbox lighting on white background\" สำหรับภาพสินค้า เพิ่ม \"rim light\" เพื่อแยกสินค้าออกจากพื้นหลัง เหมาะกับ e-commerce","feature":"image","category":"lighting","is_active":true,"created_at":"2026-02-18T09:27:56.899401+00:00","sort_order":11,"updated_at":"2026-02-18T09:27:56.899401+00:00","applicable_models":null,"applicable_platforms":["shopee","lazada"]},{"id":"0e92b56a-2c8f-4761-a32d-b9fd8d57b9a0","tags":["lighting","dramatic","mood"],"title":"Dramatic & Moody Lighting","content":"ใช้ \"chiaroscuro lighting\" หรือ \"dramatic side lighting with deep shadows\" สำหรับภาพที่ต้องการความดราม่า เพิ่ม \"volumetric light\" สำหรับแสงลำแสง","feature":"image","category":"lighting","is_active":true,"created_at":"2026-02-18T09:27:56.899401+00:00","sort_order":12,"updated_at":"2026-02-18T09:27:56.899401+00:00","applicable_models":null,"applicable_platforms":null},{"id":"c6c8a190-92a3-4acf-bee6-db4e901a8af6","tags":["lighting","neon","cyberpunk"],"title":"Neon & Cyberpunk Lighting","content":"ใช้ \"neon glow lighting\" หรือ \"cyberpunk neon signs reflecting on wet street\" เหมาะกับ content สไตล์ futuristic, gaming, nightlife","feature":"image","category":"lighting","is_active":true,"created_at":"2026-02-18T09:27:56.899401+00:00","sort_order":13,"updated_at":"2026-02-18T09:27:56.899401+00:00","applicable_models":null,"applicable_platforms":["tiktok","instagram"]},{"id":"6f557d85-5d6d-4114-ad2b-4cd9f72a9a25","tags":["model","mystic","creative"],"title":"Mystic - Best Practices","content":"Mystic เหมาะกับภาพสไตล์ artistic และ creative ใช้ prompt ที่เน้น mood และ atmosphere เช่น \"ethereal dreamy portrait\" หรือ \"surreal fantasy landscape\" รองรับ aspect ratio หลากหลาย","feature":"image","category":"model_tips","is_active":true,"created_at":"2026-02-18T09:27:56.899401+00:00","sort_order":20,"updated_at":"2026-02-18T09:27:56.899401+00:00","applicable_models":["mystic"],"applicable_platforms":null},{"id":"31a947ba-3b26-4caa-b7c8-b9c70a36691c","tags":["model","flux","photorealistic"],"title":"Flux 2 Pro - Photorealistic","content":"Flux 2 Pro เหมาะกับภาพ photorealistic สูง ใช้คำว่า \"photorealistic\" \"8K resolution\" \"hyperdetailed\" ให้ผลดี เหมาะสำหรับ product photography และ portrait","feature":"image","category":"model_tips","is_active":true,"created_at":"2026-02-18T09:27:56.899401+00:00","sort_order":21,"updated_at":"2026-02-18T09:27:56.899401+00:00","applicable_models":["flux-2-pro"],"applicable_platforms":null},{"id":"b3c89138-7e8c-42af-804c-7d5f2decb194","tags":["model","seedream","asian","thai"],"title":"Seedream V3 - Asian Content","content":"Seedream เก่งเรื่อง Asian faces และ cultural content ใช้สำหรับ portrait คนเอเชีย, อาหารไทย, สินค้า local ให้ผลที่ดูเป็นธรรมชาติกว่า model อื่น","feature":"image","category":"model_tips","is_active":true,"created_at":"2026-02-18T09:27:56.899401+00:00","sort_order":22,"updated_at":"2026-02-18T09:27:56.899401+00:00","applicable_models":["seedream-v3","seedream-v4-5"],"applicable_platforms":null},{"id":"0ea0ace9-4de2-4073-bcf3-6bd427fd1712","tags":["camera","zoom","product"],"title":"Slow Zoom In - สร้างความสนใจ","content":"ใช้ \"slow zoom in\" หรือ \"gradual push in\" เพื่อดึงความสนใจไปที่วัตถุหลัก เหมาะกับ product reveal หรือ dramatic moment เป็นเทคนิคพื้นฐานที่ใช้ได้กับทุก content","feature":"video","category":"camera_movement","is_active":true,"created_at":"2026-02-18T09:27:56.899401+00:00","sort_order":30,"updated_at":"2026-02-18T09:27:56.899401+00:00","applicable_models":null,"applicable_platforms":["tiktok","instagram","youtube"]},{"id":"27f1bef9-2f78-48ae-9686-f3b3198a5c5a","tags":["camera","orbit","product","360"],"title":"Orbit Shot - แสดงสินค้า 360°","content":"ใช้ \"orbiting camera\" หรือ \"360 degree rotation around subject\" เพื่อโชว์สินค้าหลายมุม เหมาะมากกับ product showcase, fashion, และ food","feature":"video","category":"camera_movement","is_active":true,"created_at":"2026-02-18T09:27:56.899401+00:00","sort_order":31,"updated_at":"2026-02-18T09:27:56.899401+00:00","applicable_models":null,"applicable_platforms":null},{"id":"caf83e0a-bac4-4400-ae74-720dd6f69f93","tags":["camera","drone","aerial","travel"],"title":"Drone Aerial Shot","content":"ใช้ \"aerial drone shot\" หรือ \"bird eye view slowly descending\" เหมาะกับ location reveal, real estate, travel content","feature":"video","category":"camera_movement","is_active":true,"created_at":"2026-02-18T09:27:56.899401+00:00","sort_order":32,"updated_at":"2026-02-18T09:27:56.899401+00:00","applicable_models":null,"applicable_platforms":["youtube","tiktok"]},{"id":"ab3b82bf-d450-4e0f-a354-82f4f2b07967","tags":["camera","static","stable"],"title":"Static + Subject Motion","content":"ใช้ \"static camera with subject walking toward camera\" กล้องอยู่นิ่งแต่วัตถุเคลื่อนไหว ให้ผลดีกับ AI video เพราะลดปัญหา artifact จากการเคลื่อนกล้อง","feature":"video","category":"camera_movement","is_active":true,"created_at":"2026-02-18T09:27:56.899401+00:00","sort_order":33,"updated_at":"2026-02-18T09:27:56.899401+00:00","applicable_models":null,"applicable_platforms":null},{"id":"8dbbe209-63ad-43f5-a778-108565b06320","tags":["pacing","hook","social"],"title":"Hook ใน 1-2 วินาทีแรก","content":"เริ่มวิดีโอด้วยภาพที่ดึงดูดทันที เช่น \"opening with dramatic reveal\" หรือ \"starting with eye-catching visual hook\" สำคัญมากสำหรับ TikTok และ Reels ที่คนเลื่อนเร็ว","feature":"video","category":"pacing","is_active":true,"created_at":"2026-02-18T09:27:56.899401+00:00","sort_order":40,"updated_at":"2026-02-18T09:27:56.899401+00:00","applicable_models":null,"applicable_platforms":["tiktok","instagram"]},{"id":"14efed55-17e5-4292-bcf2-bb46a660d248","tags":["pacing","product","structure","demo"],"title":"Product Demo Structure","content":"โครงสร้างวิดีโอสินค้า: Hook (0-2s) → Problem (2-4s) → Solution/Demo (4-8s) → CTA (8-10s) ใช้ \"cinematic product showcase\" เป็น base prompt แล้วเพิ่มรายละเอียด","feature":"video","category":"pacing","is_active":true,"created_at":"2026-02-18T09:27:56.899401+00:00","sort_order":41,"updated_at":"2026-02-18T09:27:56.899401+00:00","applicable_models":null,"applicable_platforms":["tiktok","instagram","youtube"]},{"id":"faa9a347-5239-4718-9c24-647cd4c46b90","tags":["model","wan","budget"],"title":"WAN 2.6 - Best All-rounder","content":"WAN 2.6 เป็น model อเนกประสงค์ ราคาถูก (per_second pricing) เหมาะกับงานทั่วไป รองรับทั้ง text-to-video และ prompt ภาษาอังกฤษ ใช้ prompt สั้นกระชับ 1-2 ประโยคให้ผลดีที่สุด","feature":"video","category":"model_tips","is_active":true,"created_at":"2026-02-18T09:27:56.899401+00:00","sort_order":50,"updated_at":"2026-02-18T09:27:56.899401+00:00","applicable_models":["wan-2-6"],"applicable_platforms":null},{"id":"5ca863eb-a2f8-4ab3-a054-ba9205a1d1c6","tags":["model","kling","premium","commercial"],"title":"Kling V3 Pro - Premium Quality","content":"Kling V3 Pro ให้คุณภาพสูงสุด เหมาะกับ commercial-grade content รองรับทั้ง text-to-video และ image-to-video ใช้ prompt ละเอียด เน้น camera movement และ lighting จะให้ผลดี","feature":"video","category":"model_tips","is_active":true,"created_at":"2026-02-18T09:27:56.899401+00:00","sort_order":51,"updated_at":"2026-02-18T09:27:56.899401+00:00","applicable_models":["kling-v3-pro"],"applicable_platforms":null},{"id":"ab4b64ca-506b-42b7-90d5-fe55f33f72ff","tags":["model","seedance","i2v","animation"],"title":"Seedance Pro - Image Animation","content":"Seedance Pro 1080p เหมาะกับ image-to-video โดยเฉพาะ ให้ภาพเคลื่อนไหวที่นุ่มนวลและสมจริง ใช้คู่กับ \"gentle motion\" หรือ \"subtle camera movement\" เพื่อผลลัพธ์ที่ดีที่สุด","feature":"video","category":"model_tips","is_active":true,"created_at":"2026-02-18T09:27:56.899401+00:00","sort_order":52,"updated_at":"2026-02-1